svg.script:
const TIPS = {
  hs1: {
    title: '① Iceberg Collision — 11:40 PM, 14 April 1912',
    lines: [
      'Starboard bow scraped ~90 m of iceberg at 22.5 knots.',
      'No single large gash. Impact popped rivet heads across',
      '6 hull sections. Total open area ~1.1 m² in thin seams.',
      'Flood ingress immediately ~400 tonnes per minute.'
    ]
  },
  hs2: {
    title: '② Rivet Failure — NIST Metallurgical Study, 1996',
    lines: [
      'Bow rivets: wrought iron with 9.3% MnS slag (max 2–3%).',
      'Slag inclusions formed brittle failure planes within iron.',
      'Under dynamic impact, rivets sheared along MnS planes',
      'rather than deforming. Seams opened; steel rivets would',
      'very likely have held under identical loading.'
    ]
  },
  hs3: {
    title: '③ Bulkhead Design Flaw',
    lines: [
      "Bulkheads ended at E-deck — no watertight top cap.",
      'Ship rated for 4 simultaneous flooded compartments.',
      '5 compartments breached; cascade was inevitable.',
      'Carlisle proposed full-height bulkheads; White Star',
      'overruled on cost / first-class accommodation grounds.'
    ]
  },
  hs4: {
    title: '④ Progressive Flooding',
    lines: [
      'BR4 had NO direct iceberg breach.',
      'Rising water in BR5 overtopped bulkhead E (~00:30 AM)',
      'and flooded BR4 purely by cascade. This domino effect',
      'continued aft, making pumping efforts futile by 01:15.'
    ]
  },
  hs5: {
    title: '⑤ Structural Breakup — 2:17 AM, 15 April 1912',
    lines: [
      'Flooding bow dragged hull to >45° (hogging condition).',
      'Keel: extreme longitudinal COMPRESSION → buckled.',
      'Boat deck: TENSION → fractured between funnels 3–4.',
      'Stern briefly righted; sank separately at 2:20 AM.',
      'Wreck lies in two sections ~600 m apart on seabed.'
    ]
  },
  hs6: {
    title: '⑥ Steel Embrittlement',
    lines: [
      'S content: 0.069% (limit 0.05%). Mn:S ratio: 6.8:1.',
      'At −2°C seawater, steel entered ductile-brittle zone.',
      'Charpy impact: 4–10 J vs 200+ J for modern steel.',
      'Plates fractured rather than bent, accelerating breakup.',
      'Source: Foecke & McCarty, "What Really Sank the Titanic" 2008.'
    ]
  }
};

const tt      = document.getElementById('tt');
const ttBg    = document.getElementById('tt-bg');
const ttBord  = document.querySelector('#tt rect:nth-child(2)');
const ttTitle = document.getElementById('tt-title');
const ttBody  = document.getElementById('tt-body');

function showTip(id, evt) {
  const tip = TIPS[id];
  if (!tip) return;
  ttTitle.textContent = tip.title;

  // Clear old body lines
  while (ttBody.firstChild) ttBody.removeChild(ttBody.firstChild);
  tip.lines.forEach((line, i) => {
    const t = document.createElementNS('http://www.w3.org/2000/svg', 'tspan');
    t.setAttribute('x', '12');
    t.setAttribute('dy', i === 0 ? '0' : '13');
    t.textContent = line;
    ttBody.appendChild(t);
  });

  const h = 28 + tip.lines.length * 13 + 8;
  ttBg.setAttribute('height', h);

  const svg   = tt.ownerSVGElement;
  const pt    = svg.createSVGPoint();
  pt.x = evt.clientX; pt.y = evt.clientY;
  const svgPt = pt.matrixTransform(svg.getScreenCTM().inverse());
  let tx = svgPt.x + 16;
  let ty = svgPt.y - 16;
  if (tx + 325 > 1080) tx = svgPt.x - 336;
  if (ty < 0) ty = 4;
  tt.setAttribute('transform', 'translate(' + tx + ',' + ty + ')');
  tt.style.display = 'block';
}

['hs1','hs2','hs3','hs4','hs5','hs6'].forEach(id => {
  const el = document.getElementById(id);
  if (!el) return;
  el.addEventListener('mouseenter', e => showTip(id, e));
  el.addEventListener('mousemove',  e => showTip(id, e));
  el.addEventListener('mouseleave', () => { tt.style.display = 'none'; });
});
